import re
import  os
import time
import datetime
import random
import requests
class XiaoMi:
 
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
        'User-Agent': 'Dalvik/2.1.0 (Linux; U; Android 5.1.1; SM-G9750 Build/LMY48Z)'
    }
 
    def __init__(self, username: str, password: str, step: str) -> None:
        self.access_code = ''
        self.app_token = ''
        self.user_id = ''
        self.username = username
        self.password = password
        self.step = step
 
    def login(self):
        '''
        登录
        '''
        url = f'https://api-user.huami.com/registrations/{self.username}/tokens'
        data = {
            'phone_number': self.username,
            'password': self.password,
            'client_id': 'HuaMi',
            'token': 'access',
            'redirect_uri': 'https://s3-us-west-2.amazonaws.com/hm-registration/successsignin.html'
        }
 
        res = requests.post(url, data=data, headers=self.headers)
        if res.status_code == 200:
            # 重定向的Location
            redirect_location = res.history[0].headers['Location']
            # 获取通行码
            find_access = re.compile(r'access=(.*?)&')
            access_code = find_access.findall(redirect_location)
            # 无论账号密码是否对得上，响应状态码都是200，但如果账号密码对不上，是没有访问码的
            if len(access_code) != 0:
                self.access_code = access_code[0]
                return True
        print(res.json())
 
    def get_token(self):
        '''
        获取令牌
        '''
        if '+86' in self.username:
            third_name = 'huami_phone'
        else:
            third_name = 'email'
        url = 'https://account.huami.com/v2/client/login'
        data = {
            'allow_registration=': 'false',
            'app_name': 'com.xiaomi.hm.health',
            'app_version': '6.3.5',
            'code': self.access_code,
            'country_code': 'CN',
            'device_id': '2C8B4939-0CCD-4E94-8CBA-CB8EA6E613A1',
            'device_model': 'phone',
            'dn': 'api-user.huami.com%2Capi-mifit.huami.com%2Capp-analytics.huami.com',
            'grant_type': 'access_token',
            'lang': 'zh_CN',
            'os_version': '1.5.0',
            'source': 'com.xiaomi.hm.health',
            'third_name': third_name,
        }
 
        res = requests.post(url, headers=self.headers, data=data)
        if res.status_code == 200:
            if len(eval(res.text)) != 1:
                token = eval(res.text)['token_info']
                self.user_id = token['user_id']
                self.app_token = token['app_token']
                return True
        print(res.json())
 
