    def generate_random_number():
        current_time = datetime.datetime.now().time()
 
        time_ranges = {
            datetime.time(7, 0): (0, 500),
            datetime.time(7, 30): (500, 1000),
            datetime.time(8, 0): (1000, 1500),
            datetime.time(8, 30): (1500, 2000),
            datetime.time(9, 0): (2000, 2500),
            datetime.time(9, 30): (2500, 3000),
            datetime.time(10, 0): (3500, 4000),
            datetime.time(10, 30): (4000, 4500),
            datetime.time(11, 30): (4500, 5000),
            datetime.time(12, 0): (5000, 5500),
            datetime.time(12, 30): (5500, 5700),
            datetime.time(13, 0): (5700, 6000),
            datetime.time(13, 30): (6000, 6500),
            datetime.time(14, 0): (6500, 7000),
            datetime.time(14, 30): (7500, 8000),
            datetime.time(15, 0): (8000, 8500),
            datetime.time(15, 30): (8500, 9000),
            datetime.time(16, 0): (9000, 9500),
            datetime.time(16, 30): (10000, 10500),
            datetime.time(17, 0): (11000, 11500),
            datetime.time(17, 30): (12000, 12500),
            datetime.time(18, 0): (12500, 13000),
            datetime.time(18, 30): (13000, 13500),
            datetime.time(19, 0): (13500, 14500),
            datetime.time(19, 30): (14500, 15500),
            datetime.time(20, 0): (15500, 16500),
            datetime.time(20, 30): (17500, 18500),
            datetime.time(21, 0): (18500, 19500),
            datetime.time(21, 30): (19500, 22778),
        }
 
        random_number = None
 
        for time_range, number_range in time_ranges.items():
            if current_time >= time_range:
                random_number = random.randint(number_range[0], number_range[1])
            else:
                break
 
        if random_number is None or current_time < datetime.time(6, 59):
            random_number = 0
 
        return random_number
 
    # 这里可以写你具体需要的运动步数，或者也可以调用generate_random_number()这个函数来根据时间生成运动步数
